import play.api.mvc._
import play.api.libs.json._
import javax.inject._

case class Order(id: Long, details: String)

class OrdersRepository {
  def getOrderById(id: Long): Option[Order] = Some(Order(id, "Sample Order Details"))
}

@Singleton
class OrdersController @Inject()(cc: ControllerComponents, ordersRepo: OrdersRepository) extends AbstractController(cc) {

  def getOrder(orderId: Long): Action[AnyContent] = Action.async {
    ordersRepo.getOrderById(orderId).map {
      case Some(order) => Ok(Json.toJson(order))
      case None => NotFound
    }
  }

